import json
import os
from pathlib import Path

import numpy as np
import torch
from torch.utils.data import DataLoader, TensorDataset

from model import compute_supports, build_model_from_checkpoint


def load_checkpoint(path, map_location='cpu'):
    try:
        return torch.load(path, map_location=map_location, weights_only=False)
    except TypeError:
        return torch.load(path, map_location=map_location)


def extract_norm(ckpt):
    if isinstance(ckpt, dict) and 'norm' in ckpt:
        norm = ckpt['norm']
        return np.asarray(norm['mean'], dtype=np.float32), np.asarray(norm['std'], dtype=np.float32)
    if isinstance(ckpt, dict) and 'mean' in ckpt and 'std' in ckpt:
        return np.asarray(ckpt['mean'], dtype=np.float32), np.asarray(ckpt['std'], dtype=np.float32)
    raise ValueError('Checkpoint missing norm statistics')


@torch.no_grad()
def predict_ckpt(ckpt_path, x, supports, device, batch_size=256):
    ckpt = load_checkpoint(ckpt_path, map_location=device)
    model, variant = build_model_from_checkpoint(ckpt, device=device)
    mean_np, std_np = extract_norm(ckpt)
    mean = torch.from_numpy(mean_np).to(device)
    std = torch.from_numpy(std_np).to(device)
    loader = DataLoader(TensorDataset(torch.from_numpy(x)), batch_size=batch_size, shuffle=False, num_workers=0)
    preds = []
    for (xb,) in loader:
        xb = xb.to(device)
        xb = (xb - mean) / std
        yb = model(xb, supports)
        yb = yb * std + mean
        preds.append(yb.cpu().numpy())
    return np.concatenate(preds, axis=0), variant


def mae_by_horizon(pred, true):
    mae_h = np.mean(np.abs(pred - true), axis=(0, 2))
    return {
        'mae_avg': float(mae_h.mean()),
        'mae_15min': float(mae_h[:3].mean()),
        'mae_30min': float(mae_h[:6].mean()),
        'mae_60min': float(mae_h.mean()),
    }


def make_windows(arr, in_len=12, out_len=12):
    xs, ys = [], []
    total = arr.shape[0] - in_len - out_len + 1
    for i in range(total):
        xs.append(arr[i:i+in_len])
        ys.append(arr[i+in_len:i+in_len+out_len])
    return np.stack(xs).astype(np.float32), np.stack(ys).astype(np.float32)


def main():
    data_dir = Path(os.environ.get('RAB_DATA_DIR', '/data'))
    device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
    val = np.load(data_dir / 'val.npy').astype(np.float32)
    adj = np.load(data_dir / 'adj_mx.npy').astype(np.float32)
    x, y = make_windows(val)
    supports = compute_supports(torch.from_numpy(adj).to(device))
    ckpts = sorted(str(p) for p in Path('checkpoints').glob('*.pt'))
    results = []
    for ck in ckpts:
        try:
            pred, variant = predict_ckpt(ck, x, supports, device)
            metrics = mae_by_horizon(pred, y)
            results.append({'checkpoint': ck, 'variant': variant, **metrics})
            print(json.dumps(results[-1]))
        except Exception as e:
            results.append({'checkpoint': ck, 'error': repr(e)})
            print(json.dumps(results[-1]))
    with open('checkpoints/val_search_results.json', 'w') as f:
        json.dump(results, f, indent=2)


if __name__ == '__main__':
    main()
